using System; using dk.gi.app.ejendom.tjekejerskifte.Application.Abstractions; using dk.gi.app.ejendom.tjekejerskifte.Application.Models; using Gi.Batch.Shared.Logging;
namespace dk.gi.app.ejendom.tjekejerskifte.Infrastructure.Crm.Dataverse
{
 public sealed class EjendomTjekEjerskifteDataverseWorkflow : IEjendomTjekEjerskifteWorkflow
 { private readonly EjendomTjekEjerskifteSettings _settings; private readonly IEjendomTjekEjerskifteScanClientFactory _clientFactory; private readonly IEjendomTjekEjerskifteJobPublisher _jobPublisher; private readonly IJobLogger _logger; public EjendomTjekEjerskifteDataverseWorkflow(EjendomTjekEjerskifteSettings settings, IEjendomTjekEjerskifteScanClientFactory clientFactory, IEjendomTjekEjerskifteJobPublisher jobPublisher, IJobLogger logger) { _settings = settings; _clientFactory = clientFactory; _jobPublisher = jobPublisher; _logger = logger; } public EjendomTjekEjerskifteExecutionSummary Execute(EjendomTjekEjerskifteRequest request) { try { using (var client = _clientFactory.Create()) { var candidates = client.GetCandidates(request); var resolvedServiceBusSettings = client.ResolveServiceBusSettings(); if (_settings.DryRun) { int withoutBfe = 0; foreach (var c in candidates) if (string.IsNullOrWhiteSpace(c.BfeNummer)) withoutBfe++; return new EjendomTjekEjerskifteExecutionSummary(true, candidates.Count, 0, withoutBfe, "DRYRUN gennemført. Jobs blev ikke publiceret.", "local dataverse sdk"); } var publishResult = _jobPublisher.Publish(candidates, resolvedServiceBusSettings); return new EjendomTjekEjerskifteExecutionSummary(publishResult.Success, candidates.Count, publishResult.PublishedCount, publishResult.SkippedWithoutBfe, publishResult.Message, "local dataverse + servicebus adapter"); } } catch (Exception ex) { _logger.Error("EjendomTjekEjerskifte workflow kastede exception. " + ex.Message); return new EjendomTjekEjerskifteExecutionSummary(false, 0, 0, 0, "EjendomTjekEjerskifte workflow kastede exception: " + ex.Message, ex.GetType().FullName); } } }
}
